import json
import urllib.request

def fetch_webpage_title(url: str) -> str:
    """Fetch the title of a webpage given its URL.

    Args:
        url: The full URL of the webpage (must start with https://).
    """
    if not url.startswith("https://"):
        return json.dumps({"error": "Only HTTPS URLs are supported."})
    try:
        with urllib.request.urlopen(url, timeout=5) as resp:
            html = resp.read(4096).decode("utf-8", errors="ignore")
        # Extract <title> tag
        start = html.lower().find("<title>")
        end = html.lower().find("</title>")
        if start != -1 and end != -1:
            title = html[start + 7:end].strip()
            return json.dumps({"url": url, "title": title})
        return json.dumps({"url": url, "title": "No title found"})
    except Exception as e:
        return json.dumps({"error": str(e)})
